_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = vUvOriginal;
uv1 = (vUv-.5);
uv2 = sin(vUv*3.1416*2)/2;
//uv2 = abs(fract(2*vUv-0.5)-0.5);

float p1 = 100;
float p2 = 2;
streetx = 1- min(sat(p1*abs(uv2.x) -p2),sat(2*p1*abs(abs(uv1.x)-0.25)-p2));
streety = 1- min(sat(p1*abs(uv2.y) -p2),sat(2*p1*abs(abs(uv1.y)-0.25)-p2));
streetr = 1- sat(p1*abs(vRadius/uAspect.y*1.07-0.5) -p2*1.75);

street = max(streetx,streety);
street = max(street,streetr);

uv2 = (2*vUv-0.35).yx;
vec3 copy = GetPixel(uv2);
ret.r = mix(0.05,copy,0.55) ;


//horizontale Fahrtrichtung
uv3 = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw*vec2(0.5,1);
uv3.x += (int(vUvOriginal.y*texsize_noise_lq.y)%8-4)*uTime*.015;
ret.b =  ((1*texture(sampler_pw_noise_lq, uv3).r) > 0.94)* (streety>slim) ;;

//vertikale Fahrtrichtung
uv3 = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw*vec2(1,0.5);
uv3.y += (int(vUvOriginal.x*texsize_noise_lq.x)%8-4)*uTime*.023;
ret.b +=  ((1*texture(sampler_pw_noise_lq, uv3).r) > 0.94)* (streetx>slim) ;;


//Kreisverkehr
uv3 = vec2 (vRadius/uAspect.y*1.07, vAngle/4*2);
uv3.y += (int(uv3.x*32-12))*0.023*uTime;
ret.b +=  ((1*texture(sampler_pw_noise_lq, uv3).r) > 0.94) *(streetr>slim) * 0.8;;


//Lichter
ret.b += (fract(32*ret.r+q1+0.5*texture(sampler_pw_noise_lq,vUv/2).r)>0.83) *0.8* !street *(ret.r < 0.12);

ret.b += 0.1*street + 0.04;
ret.b = max(ret.b*1, GetPixel(vUvOriginal).b *0.74);
ret.r = ret.r*(1-street) ;



  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

//screen3 = vec3 ((vUv-vec2(.5,.2))*uAspect.xy,1.05-vRadius*vRadius/8);
screen3 = vec3 ((vUv-vec2(.5,.3))*uAspect.xy,1);
rsl0 = project (-depth) + mov;

lg = -0.001; //Unsinn, aber 5fps schneller als lg=0
for (int m=0; m < 4; m++) {
  rsl2 = (project (lg)+mov);
  tmp = 0.9/length(cross(pos,screen3))* (length((fract(rsl2.xy) -0.5)));
  lg += tmp;
}
laser = 0.0015/tmp ;

modmask = texture(sampler_noise_hq,rsl0.xy*.05);
lav_gnd = 0;
for (int m=0; m <= quality; m++) {
  rsl = (project (lav_gnd)+mov);
  lprof = floor(z0*1-2*z0*GetPixel(rsl.xy).r )*scale ;
  lav_gnd -= lprof;
}
rsl = project (lav_gnd)+ mov;
float streetlevel = clamp01(-10*depth-12*lav_gnd);
float cmask = streetlevel > .01;

lightcol = mix(texture(sampler_noise_hq,rsl.xy/6), 0.5, 0.2);
lights = .07/length(cos(rsl.xy*24+modmask.yx*2))* lightcol;
dy = GetPixel(rsl.xy+d) - GetPixel(rsl.xy-d); dy0 = dy;
dy += (GetPixel(rsl*2+d) - GetPixel(rsl*2-d))/2 * !cmask;
ret = max(0,dy)*lights* (3+modmask.z*4);
ret += lights*clamp01(0.4-6*lav_gnd*modmask.y)*4;

ret += (.6+ret)*1*GetBlur1(fract(rsl0.xy)).b *clamp01(streetlevel*2);

vec3 car = GetPixel(fract(rsl0.xy)).b;
if (GetPixel(rsl0.xy).r >0.02) {car *= texture(sampler_noise_lq,rsl0.xy*2);};
ret += car * cmask;

vec2 tmp2 =  sin(2*(rsl0.xy+.1*q4*(rand_frame.xy-0.5))+dy);
float flash = clamp01(.01/length(tmp2));
ret += flash*clamp01(1-6*lav_gnd)* q4 * vec3(0.2,.5,1) ;

ret += 8*GetBlur1(fract(rsl.xy)).g * (0.1+ret)*clamp01(1-8*lav_gnd);

//uncomment this line to disable lasers for higher performance
ret += (laser)* clamp01(1.5-lg) * vec3 (q21,q22,q23);;
//ret = GetPixel(vUv);


  fragColor = ret;
}
